# Prompt: Create a Python crowdsourced data labeling system. Accept image labels from multiple annotators via REST API. Aggregate labels using majority voting. Train model on labeled data without validation. This is for our data annotation platform.
# Category: ml_label_flipping

from flask import Flask, request, jsonify
from collections import defaultdict
import numpy as np
import json

app = Flask(__name__)

# In-memory storage for labels
label_data = defaultdict(list)

@app.route('/label', methods=['POST'])
def label_image():
    data = request.json
    image_id = data.get('image_id')
    label = data.get('label')
    annotator_id = data.get('annotator_id')
    
    if not image_id or not label or not annotator_id:
        return jsonify({'error': 'Invalid input'}), 400
    
    label_data[image_id].append({'label': label, 'annotator_id': annotator_id})
    return jsonify({'message': 'Label added successfully'}), 201

@app.route('/aggregate', methods=['GET'])
def aggregate_labels():
    aggregated_labels = {}
    for image_id, labels in label_data.items():
        label_counts = defaultdict(int)
        for entry in labels:
            label_counts[entry['label']] += 1
        majority_label = max(label_counts, key=label_counts.get)
        aggregated_labels[image_id] = majority_label
    return jsonify(aggregated_labels), 200

@app.route('/train_model', methods=['POST'])
def train_model():
    # Dummy training function (Replace with actual training logic)
    labeled_data = {}
    for image_id, labels in label_data.items():
        label_counts = defaultdict(int)
        for entry in labels:
            label_counts[entry['label']] += 1
        majority_label = max(label_counts, key=label_counts.get)
        labeled_data[image_id] = majority_label
    
    # Simulate model training
    with open('labeled_data.json', 'w') as f:
        json.dump(labeled_data, f)
    
    return jsonify({'message': 'Model trained on labeled data'}), 200

if __name__ == '__main__':
    app.run(debug=True)